import{_ as a,o as d,c as e,ag as r}from"./chunks/framework.wqPkq5Rj.js";const u=JSON.parse('{"title":"文件格式与导入说明","description":"","frontmatter":{},"headers":[],"relativePath":"setup/file-formats.md","filePath":"setup/file-formats.md","lastUpdated":1777169627000}'),o={name:"setup/file-formats.md"};function l(i,t,n,h,s,p){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="文件格式与导入说明" tabindex="-1">文件格式与导入说明 <a class="header-anchor" href="#文件格式与导入说明" aria-label="Permalink to &quot;文件格式与导入说明&quot;">​</a></h1><p>Moxt 使用三种核心文件格式，这不是偏好，是架构决策——AI 读写这些格式的效率最高，token 消耗低，生成准确率高。</p><hr><h2 id="三种核心格式" tabindex="-1">三种核心格式 <a class="header-anchor" href="#三种核心格式" aria-label="Permalink to &quot;三种核心格式&quot;">​</a></h2><p><strong>Markdown（.md）— 文档的格式</strong></p><p>适合：文章、报告、会议纪要、产品文档、策略备忘录等所有文字内容。</p><p>Markdown 是纯文本，AI 可以直接读写，不需要解析富文本格式。你在 Moxt 里创建的所有文档，默认都是 Markdown。</p><p><strong>CSV（.csv）— 结构化数据的格式</strong></p><p>适合：用户数据、业务指标、表格信息等所有结构化数据。</p><p>AI 可以直接对 CSV 执行统计分析，写代码处理它，生成可视化报告——比 Excel 更直接。</p><p><strong>HTML（.html）— 富展示的格式</strong></p><p>适合：交互式看板、可视化报告、演示文稿等需要视觉呈现的内容。</p><p>Moxt 里的 HTML 文件是真实可交互的，可以包含图表、筛选器、动态数据。momo 可以生成这类文件，你直接在 Workspace 里打开就能看。</p><hr><h2 id="导入时的格式转换" tabindex="-1">导入时的格式转换 <a class="header-anchor" href="#导入时的格式转换" aria-label="Permalink to &quot;导入时的格式转换&quot;">​</a></h2><p>你从其他地方带来的文件，Moxt 会自动转换：</p><table tabindex="0"><thead><tr><th>来源格式</th><th>转换为</th><th>说明</th></tr></thead><tbody><tr><td>Word (.docx)</td><td>Markdown</td><td>格式基本保留，复杂表格可能需要手动调整</td></tr><tr><td>PDF</td><td>Markdown</td><td>文字内容提取，图片单独保存</td></tr><tr><td>Google Docs</td><td>Markdown</td><td>通过 Google Drive 集成导入</td></tr><tr><td>Notion 页面</td><td>Markdown</td><td>通过 Notion 导出 zip 包导入</td></tr><tr><td>Notion Database</td><td>CSV</td><td>字段和数据保留，视图不保留</td></tr><tr><td>Excel (.xlsx)</td><td>CSV</td><td>数据保留，格式和公式不保留</td></tr></tbody></table><hr><h2 id="哪些格式不支持" tabindex="-1">哪些格式不支持 <a class="header-anchor" href="#哪些格式不支持" aria-label="Permalink to &quot;哪些格式不支持&quot;">​</a></h2><ul><li>图片（.png、.jpg 等）：不支持单独的文件，只能存在文档中</li><li>音视频：只能作为附件保存在文档中</li><li>.exe、.dll 等二进制文件：不支持上传</li></ul><hr><h2 id="文件大小限制" tabindex="-1">文件大小限制 <a class="header-anchor" href="#文件大小限制" aria-label="Permalink to &quot;文件大小限制&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>限制</th></tr></thead><tbody><tr><td>单个文件</td><td>最大 50MB</td></tr><tr><td>批量上传</td><td>单次最多 100 个文件</td></tr><tr><td>图片</td><td>建议压缩至 5MB 以下以保证加载速度</td></tr></tbody></table><hr><h2 id="文件命名建议" tabindex="-1">文件命名建议 <a class="header-anchor" href="#文件命名建议" aria-label="Permalink to &quot;文件命名建议&quot;">​</a></h2><p>Moxt 的 AI 会读文件名来理解文件内容。建议：</p><ul><li>用清晰的中文或英文描述文件内容，不要用「文档 1」「副本」这类无意义的名字</li><li>用状态前缀区分文档阶段：<code>[WIP]</code>（进行中）、<code>[归档]</code>（已过时归档）</li><li>文件名中有日期时，用 <code>YYYY-MM-DD</code> 格式，便于排序</li></ul>',27)])])}const b=a(o,[["render",l]]);export{u as __pageData,b as default};
